mapper.update:
update orders
status = #{status}, update_time = #{updateTime}, update_user = #{updateUser},
where order_id = #{orderId}

mapper.select:
select o.order_id, o.item_id, o.amount, o.status, o.create_time, o.buyer_id, o.seller_id, i.title as item_title, i.image_url as item_image_url, b.username as buyer_name, s.username as seller_name from orders o left join item i on o.item_id = i.item_id left join user b on o.buyer_id = b.user_id left join user s on o.seller_id = s.user_id
and o.buyer_id = #{buyerId} and o.seller_id = #{sellerId} and o.status = #{status}
order by o.create_time desc
